WebLink.url:
{!URLFOR( $Site.BaseUrl & '/apex/dfsle__CustomEnvelopeCreation', null, [ sId = Contract.Id, CCTM = 'HR CC~Receives a Copy', CES = Contract.Clinician_First_Name__c & ' ' & Contract.Clinician_Last_Name__c & ' - contract documents - ' & TEXT(Contract.StartDate) , CCRM = 'Customer Signer~Signer 1;Role~Company Signer~Signer 2',
CRL = /* Customer Signer */ 'Email~' & Contract.Clinician_Email__c & ';FirstName~' & Contract.Clinician_First_Name__c & ';LastName~' & Contract.Clinician_Last_Name__c & ';Role~Signer 1;RoutingOrder~1'
/* Company Signer */ & ',Email~' & $Setup.DocuSign_For_Contracting_Setting__c.Email__c & ';FirstName~' & $Setup.DocuSign_For_Contracting_Setting__c.First_Name__c & ';LastName~' & $Setup.DocuSign_For_Contracting_Setting__c.Last_Name__c & ';Role~Signer 2;RoutingOrder~2'
/* HR CC from Hierarchy Custom Setting ($Setup) */ & IF( TEXT(Contract.Employment_Type__c) = 'Employee', ',Email~' & $Setup.DocuSign_For_Contracting_Setting__c.HR_Email__c & ';LastName~' & $Setup.DocuSign_For_Contracting_Setting__c.HR_Last_Name__c & ';Role~HR CC;RoutingOrder~1', '' ),
RES = '1,3,3,1,60,3', LA = 0, CFS = 'Envelope Name~' + Contract.Clinician_First_Name__c & ' ' & Contract.Clinician_Last_Name__c & ' - contract documents - ' & TEXT(Contract.StartDate) + '~1~1,Document Type~Clinician Agreement~1~1' ] )}
